var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐?! 그런 게 어딨어!","JPN":"はあ！？　そんなのおかしいだろ！","ENG":"What?! That's such a rip-off!","TWN":"什麼？！哪有這樣的！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BAR_NPC_HAVEN_NULL","text":{"KOREA":"손님, 조심해 주세요. 손실이 나면 저희가 전액 변상해야……","JPN":"お客様、お気を付けください。壊れた際には私たちで全額弁償しないといけませんので……","ENG":"Ma'am, please. If it's damaged, then we'll have to pay out of our pocket–","TWN":"客人，麻煩小心一點，萬一有什麼損失，我們是要全額賠償……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"BAR_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BAR_NPC_HAVEN_NULL","text":{"KOREA":"죄, 죄송합니다. 피곤해서 정신이 없다 보니 말실수를 했어요.","JPN":"も、も、申し訳ございません。疲れていたので、つい失言を。","ENG":"M-my apologies. I'm so tired and distracted that it just slipped out.","TWN":"抱…抱歉，是我太累說錯話。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"BAR_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"아. 아냐. 나야말로 미안.","JPN":"い、いや。私こそごめん。","ENG":"No, don't worry about it. I should be the one apologizing to you.","TWN":"沒…沒有啦，我才對你不好意思。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"하지만 도전장 한 장에 10만 헤이븐 코인이라니 너무하잖아.","JPN":"でも挑戦状1枚が10万ヘイブンコインなんてあんまりだ。","ENG":"But seriously? We have to pay 100k Haven Coins to enter the challenge?","TWN":"不過一張挑戰券竟然要10萬天堂幣，這是在搶劫嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"시작부터 글렀네.","JPN":"最初からダメダメだね。","ENG":"Guess that's out of the picture.","TWN":"一開始就踢到鐵板呢。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"헤이븐 코인이 뭐야?","JPN":"ヘイブンコインってなに？","ENG":"What's a Haven Coin?","TWN":"天堂幣是什麼？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"헤이븐 랜드에서 크레딧처럼 쓰는 거래 수단이야.","JPN":"ヘイブンランドでお金のように使われる取引手段だよ。","ENG":"It's money, like Credit, that's used in Havenland.","TWN":"是可以在天堂樂園中使用的一種交易貨幣。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"10만이면 큰 액수이긴 해. 작은 집도 살 수 있을 정도로.","JPN":"10万といえば大金ではあるんだ。小さな家を一軒買えるくらいだから。","ENG":"And 100k is a lot of it. You could buy a small house with that amount.","TWN":"10萬是蠻多的，價值幾乎可以買下一間小套房。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오. 그렇구나.","JPN":"おお、そうなんだ。","ENG":"Ooh... I see.","TWN":"哇喔，原來是這樣。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠가 그랬어. 아빠처럼 청렴한 사람들은 자기 힘으로 돈을 버는 게 재미있대.","JPN":"パパがこう言ってたよ。パパのように正しい人たちは、自分の力でお金を稼ぐのが楽しいんだって。","ENG":"Here's what Daddy told me. Daddy said that people with integrity like him have fun making money on their own!","TWN":"爸爸說過，像爸爸那樣清廉的人，都認為靠自己的力量賺錢才有趣。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"우리 다 같이 힘내서 10만 헤이븐 코인을 모아 보자! 분명 재밌을 거야!","JPN":"みんなで頑張って10万ヘイブンコインを集めてみようよ！　きっと面白いよ！","ENG":"So let's all work together and try to make 100k Haven Coins! It'll be fun!","TWN":"我們也一起努力賺到10萬天堂幣吧！一定會很有趣！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"맞아! 게임에 이기기만 하면 가지고 있는 헤이븐 코인을 잔뜩 늘릴 수 있으니까!","JPN":"そうだよ！　ゲームに勝ちさえすれば、手持ちのヘイブンコインをいっぱい増やせるから！","ENG":"She's right! You can earn a lot of coins by winning games here!","TWN":"沒錯！只要玩遊戲獲勝，我們手上的天堂幣一定會越來越多的！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"좋은 생각이긴 한데, 한 가지 치명적인 문제가 있어.","JPN":"いい考えではあるけど、一つだけクリティカルな問題がある。","ENG":"That's a good idea and all, but there's one critical problem.","TWN":"樂觀是很好，但現在有個致命的問題。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그게 뭔데?","JPN":"どんな？","ENG":"What's that?","TWN":"什麼問題？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"우리에게는 헤이븐 코인이 하나도 없거든.","JPN":"実はヘイブンコインが一枚もないんだ。","ENG":"We don't have a single Haven Coin left.","TWN":"我們根本連一個天堂幣都沒有。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"어어? 그럴 리가? 승선할 때 받지 않았어?","JPN":"ええ？　そんな！　乗船する時もらわなかった？","ENG":"H-huh? No way... Didn't you get some when you came on board the ship?","TWN":"蛤？真的假的？上船的時候沒拿到嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};